-- Migration 007: Seed rich Google ADK templates (matching Strands template quality)
-- Requires: Migration 006 (framework column exists)
-- Created: 2026-07-14

-- Remove old ADK seed templates from 006 (we're replacing with richer versions)
DELETE FROM flow_templates WHERE framework = 'google-adk';

INSERT INTO flow_templates (`template_id`, `name`, `description`, `framework`, `category`, `pattern`, `difficulty`, `tags`, `source_url`, `source_author`, `is_official`, `is_published`, `flow_data`) VALUES

-- ═══════════════════════════════════════════════════════════════
-- Template 1: Single Agent + Tools (ADK equivalent of Production Agent)
-- ═══════════════════════════════════════════════════════════════
('adk-production-agent', 'Production-Ready ADK Agent (Full Features)', 'Demonstrates key ADK features: LlmAgent with callbacks (guardrails), FunctionTool, Google Search, session state, output_key, and GenerateContentConfig. The ADK equivalent of the Strands production agent.', 'google-adk', 'single-agent', NULL, 'intermediate', '["production", "callbacks", "guardrails", "tools", "session", "state", "adk"]', 'https://google.github.io/adk-docs/agents/llm-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"User Request"}},{"id":"agent_1","type":"adk-llm-agent","position":{"x":400,"y":180},"data":{"label":"Production Agent","name":"production_agent","model":"gemini-2.0-flash","modelProvider":"gemini","instruction":"You are a production-grade AI assistant. Use available tools to research and provide accurate answers. Always verify information before responding.","description":"Main production agent with guardrails","outputKey":"last_response","beforeModelCallback":true,"afterModelCallback":true,"temperature":0.7,"maxOutputTokens":4096,"topP":0.95,"sessionType":"in-memory"}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":380,"y":40},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"tool_custom","type":"adk-function-tool","position":{"x":600,"y":40},"data":{"label":"Validate Data","functionName":"validate_data","description":"Validate and sanitize user-provided data before processing","code":"    import re\\n    # Sanitize input\\n    cleaned = re.sub(r''[<>]'', '''', query)\\n    return {\"valid\": True, \"cleaned_query\": cleaned}"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":220},"data":{"label":"Verified Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent_1","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e3","source":"tool_custom","target":"agent_1","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e4","source":"agent_1","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 2: Sequential Pipeline (Research → Write → Review)
-- ═══════════════════════════════════════════════════════════════
('adk-sequential-pipeline', 'Research-Write-Review Pipeline (Sequential)', 'Three-stage sequential pipeline: Researcher gathers information, Writer produces content, Reviewer polishes it. Each agent passes results to the next via output_key and session state.', 'google-adk', 'custom', 'Sequential', 'beginner', '["sequential", "pipeline", "research", "writing", "review", "adk", "workflow"]', 'https://google.github.io/adk-docs/agents/workflow-agents/sequential-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Topic"}},{"id":"researcher","type":"adk-llm-agent","position":{"x":280,"y":80},"data":{"label":"Researcher","name":"researcher","model":"gemini-2.0-flash","instruction":"Research the given topic thoroughly. Find key facts, statistics, and expert opinions. Save your findings for the writer.","outputKey":"research_notes"}},{"id":"writer","type":"adk-llm-agent","position":{"x":280,"y":220},"data":{"label":"Writer","name":"writer","model":"gemini-2.0-flash","instruction":"Using the research notes in state, write a well-structured article. Include introduction, main points, and conclusion. Save as draft.","outputKey":"draft"}},{"id":"reviewer","type":"adk-llm-agent","position":{"x":280,"y":360},"data":{"label":"Reviewer","name":"reviewer","model":"gemini-2.0-flash","instruction":"Review the draft for clarity, accuracy, and grammar. Provide the final polished version ready for publication.","outputKey":"final_article"}},{"id":"pipeline","type":"adk-sequential","position":{"x":560,"y":220},"data":{"label":"Content Pipeline","name":"content_pipeline","description":"Research → Write → Review (sequential)"}},{"id":"output_1","type":"adk-output","position":{"x":800,"y":220},"data":{"label":"Published Article"}}],"edges":[{"id":"e1","source":"input_1","target":"pipeline","animated":true},{"id":"e2","source":"researcher","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e3","source":"writer","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e4","source":"reviewer","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e5","source":"pipeline","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 3: Parallel Multi-Source Data Gathering
-- ═══════════════════════════════════════════════════════════════
('adk-parallel-gatherer', 'Multi-Source Intelligence Gatherer (Parallel)', 'Parallel agent dispatches to 4 specialized sources simultaneously: news, academic, financial, and social. Results aggregated by a synthesizer. Demonstrates concurrent execution with output_key state passing.', 'google-adk', 'custom', 'Parallel', 'intermediate', '["parallel", "multi-source", "intelligence", "concurrent", "aggregation", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/parallel-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":250},"data":{"label":"Research Topic"}},{"id":"news","type":"adk-llm-agent","position":{"x":280,"y":60},"data":{"label":"News Agent","name":"news_agent","model":"gemini-2.0-flash","instruction":"Search for and summarize the latest news articles related to the topic. Focus on developments from the past month.","outputKey":"news_results"}},{"id":"academic","type":"adk-llm-agent","position":{"x":280,"y":180},"data":{"label":"Academic Agent","name":"academic_agent","model":"gemini-2.0-flash","instruction":"Find and summarize relevant academic papers and research. Focus on peer-reviewed sources and key findings.","outputKey":"academic_results"}},{"id":"financial","type":"adk-llm-agent","position":{"x":280,"y":300},"data":{"label":"Financial Agent","name":"financial_agent","model":"gemini-2.0-flash","instruction":"Analyze financial implications, market data, and economic indicators related to the topic.","outputKey":"financial_results"}},{"id":"social","type":"adk-llm-agent","position":{"x":280,"y":420},"data":{"label":"Social Agent","name":"social_agent","model":"gemini-2.0-flash","instruction":"Analyze public sentiment, social media discussions, and community opinions on the topic.","outputKey":"social_results"}},{"id":"gatherer","type":"adk-parallel","position":{"x":560,"y":250},"data":{"label":"Data Gatherer","name":"intelligence_gatherer","description":"Dispatches to all 4 sources concurrently"}},{"id":"synthesizer","type":"adk-llm-agent","position":{"x":800,"y":250},"data":{"label":"Synthesizer","name":"synthesizer","model":"gemini-2.5-pro","instruction":"You have results from news, academic, financial, and social analysis in the session state. Synthesize all sources into a comprehensive intelligence briefing with executive summary, key findings by source, and actionable recommendations.","outputKey":"briefing"}},{"id":"output_1","type":"adk-output","position":{"x":1060,"y":250},"data":{"label":"Intelligence Briefing"}}],"edges":[{"id":"e1","source":"input_1","target":"gatherer","animated":true},{"id":"e2","source":"news","target":"gatherer","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e3","source":"academic","target":"gatherer","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e4","source":"financial","target":"gatherer","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e5","source":"social","target":"gatherer","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e6","source":"gatherer","target":"synthesizer","animated":true},{"id":"e7","source":"synthesizer","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 4: Writer-Reviewer Loop (Iterative Refinement)
-- ═══════════════════════════════════════════════════════════════
('adk-feedback-loop', 'Writer-Reviewer Feedback Loop (Loop Agent)', 'Iterative refinement pattern: Writer drafts content, Critic evaluates and provides feedback. Loop continues until Critic escalates (approves). Max 5 iterations as safety limit.', 'google-adk', 'custom', 'Loop', 'intermediate', '["loop", "feedback", "iterative", "refinement", "writer", "reviewer", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/loop-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":200},"data":{"label":"Writing Brief"}},{"id":"writer","type":"adk-llm-agent","position":{"x":280,"y":120},"data":{"label":"Content Writer","name":"writer","model":"gemini-2.0-flash","instruction":"Write or revise content based on the brief and any feedback received. Check state for previous feedback. Aim for clarity, engagement, and accuracy.","outputKey":"current_draft"}},{"id":"critic","type":"adk-llm-agent","position":{"x":280,"y":300},"data":{"label":"Quality Critic","name":"critic","model":"gemini-2.5-pro","instruction":"Review the current draft critically. Score it 1-10 on clarity, accuracy, engagement. If score >= 8, respond ONLY with ''APPROVED'' and escalate to end the loop. Otherwise provide specific, actionable feedback for improvement.","outputKey":"feedback"}},{"id":"loop","type":"adk-loop","position":{"x":540,"y":200},"data":{"label":"Refinement Loop","name":"refinement_loop","description":"Write → Critique → Repeat until APPROVED","maxIterations":5}},{"id":"output_1","type":"adk-output","position":{"x":780,"y":200},"data":{"label":"Approved Content"}}],"edges":[{"id":"e1","source":"input_1","target":"loop","animated":true},{"id":"e2","source":"writer","target":"loop","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e3","source":"critic","target":"loop","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e4","source":"loop","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 5: MCP-Powered Agent (External Tools)
-- ═══════════════════════════════════════════════════════════════
('adk-mcp-agent', 'MCP-Powered Research Agent (External Tools)', 'Single agent connected to multiple MCP servers: filesystem access (stdio) and a web API server (SSE). Demonstrates MCPToolset integration with both transport types.', 'google-adk', 'single-agent', 'Single + MCP', 'intermediate', '["mcp", "tools", "filesystem", "api", "stdio", "sse", "research", "adk"]', 'https://google.github.io/adk-docs/tools-custom/mcp-tools/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Research Query"}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":300,"y":50},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"mcp_fs","type":"adk-mcp-tool","position":{"x":300,"y":390},"data":{"label":"Filesystem (stdio)","serverName":"filesystem","transport":"stdio","command":"npx -y @modelcontextprotocol/server-filesystem /tmp/research"}},{"id":"mcp_api","type":"adk-mcp-tool","position":{"x":540,"y":390},"data":{"label":"API Server (SSE)","serverName":"api_server","transport":"sse","url":"http://localhost:3001/sse"}},{"id":"fn_summarize","type":"adk-function-tool","position":{"x":540,"y":50},"data":{"label":"Summarize Text","functionName":"summarize_text","description":"Truncate and summarize long text to key points","code":"    if len(query) > 2000:\\n        return {\"summary\": query[:2000] + \"... [truncated]\", \"word_count\": len(query.split())}\\n    return {\"summary\": query, \"word_count\": len(query.split())}"}},{"id":"agent","type":"adk-llm-agent","position":{"x":420,"y":220},"data":{"label":"Research Agent","name":"research_agent","model":"gemini-2.0-flash","instruction":"You are a thorough research agent with web search, file system access, API access, and text summarization. Search the web, save findings to files, query APIs for data, and summarize long content. Cite all sources.","outputKey":"research_output"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":220},"data":{"label":"Research Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e3","source":"mcp_fs","target":"agent","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e4","source":"mcp_api","target":"agent","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e5","source":"fn_summarize","target":"agent","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e6","source":"agent","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 6: Orchestrator with Sub-Agents (Agent Routing)
-- ═══════════════════════════════════════════════════════════════
('adk-orchestrator-routing', 'Customer Support Orchestrator (Agent Routing)', 'An LlmAgent that routes requests to specialized sub-agents based on the query type. Demonstrates ADK sub_agents for delegation — the ADK equivalent of Agents-as-Tools.', 'google-adk', 'custom', 'Routing', 'intermediate', '["orchestrator", "routing", "sub-agents", "customer-support", "delegation", "adk"]', 'https://google.github.io/adk-docs/agents/llm-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Customer Query"}},{"id":"router","type":"adk-llm-agent","position":{"x":360,"y":200},"data":{"label":"Support Router","name":"support_router","model":"gemini-2.0-flash","instruction":"You are a customer support router. Based on the query:\\n- Technical issues → delegate to tech_support\\n- Billing questions → delegate to billing_support\\n- General inquiries → delegate to general_support\\n\\nAlways route to the most appropriate specialist.","description":"Routes queries to appropriate specialist"}},{"id":"tech","type":"adk-llm-agent","position":{"x":700,"y":80},"data":{"label":"Tech Support","name":"tech_support","model":"gemini-2.0-flash","instruction":"You are a technical support specialist. Help with software bugs, configuration issues, API problems, and deployment troubleshooting. Provide step-by-step solutions.","description":"Handles technical issues"}},{"id":"billing","type":"adk-llm-agent","position":{"x":700,"y":220},"data":{"label":"Billing Support","name":"billing_support","model":"gemini-2.0-flash","instruction":"You are a billing specialist. Help with invoices, payment issues, subscription changes, refunds, and pricing questions. Always confirm amounts before any changes.","description":"Handles billing questions"}},{"id":"general","type":"adk-llm-agent","position":{"x":700,"y":360},"data":{"label":"General Support","name":"general_support","model":"gemini-2.0-flash","instruction":"You handle general customer inquiries: account information, feature requests, feedback, and anything that doesn''t fit tech or billing categories.","description":"Handles general inquiries"}},{"id":"output_1","type":"adk-output","position":{"x":360,"y":420},"data":{"label":"Support Response"}}],"edges":[{"id":"e1","source":"input_1","target":"router","targetHandle":"input","animated":true},{"id":"e2","source":"router","sourceHandle":"sub-agents","target":"tech","animated":true,"label":"sub-agent"},{"id":"e3","source":"router","sourceHandle":"sub-agents","target":"billing","animated":true,"label":"sub-agent"},{"id":"e4","source":"router","sourceHandle":"sub-agents","target":"general","animated":true,"label":"sub-agent"},{"id":"e5","source":"router","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 7: Nested Workflow (Sequential + Parallel)
-- ═══════════════════════════════════════════════════════════════
('adk-nested-workflow', 'Nested Workflow (Sequential + Parallel)', 'Complex workflow combining Sequential and Parallel agents. Outer sequential pipeline with an inner parallel stage. Demonstrates composable workflow patterns.', 'google-adk', 'custom', 'Nested', 'advanced', '["nested", "sequential", "parallel", "composable", "complex", "workflow", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":250},"data":{"label":"Project Brief"}},{"id":"planner","type":"adk-llm-agent","position":{"x":260,"y":250},"data":{"label":"Project Planner","name":"planner","model":"gemini-2.0-flash","instruction":"Break down the project brief into discrete tasks. Identify what can be done in parallel vs what has dependencies.","outputKey":"project_plan"}},{"id":"dev_frontend","type":"adk-llm-agent","position":{"x":500,"y":120},"data":{"label":"Frontend Dev","name":"frontend_dev","model":"gemini-2.0-flash","instruction":"Implement the frontend components described in the project plan. Write React/TypeScript code.","outputKey":"frontend_code"}},{"id":"dev_backend","type":"adk-llm-agent","position":{"x":500,"y":250},"data":{"label":"Backend Dev","name":"backend_dev","model":"gemini-2.0-flash","instruction":"Implement the backend API described in the project plan. Write Python/FastAPI code.","outputKey":"backend_code"}},{"id":"dev_tests","type":"adk-llm-agent","position":{"x":500,"y":380},"data":{"label":"Test Writer","name":"test_writer","model":"gemini-2.0-flash","instruction":"Write comprehensive tests for both frontend and backend code described in the plan.","outputKey":"test_code"}},{"id":"parallel_dev","type":"adk-parallel","position":{"x":740,"y":250},"data":{"label":"Parallel Development","name":"parallel_dev","description":"Frontend + Backend + Tests run simultaneously"}},{"id":"integrator","type":"adk-llm-agent","position":{"x":960,"y":250},"data":{"label":"Integrator","name":"integrator","model":"gemini-2.5-pro","instruction":"Review all code from frontend, backend, and tests in session state. Verify they integrate correctly, check for inconsistencies, and produce a final integration report.","outputKey":"integration_report"}},{"id":"pipeline","type":"adk-sequential","position":{"x":1180,"y":250},"data":{"label":"Full Pipeline","name":"project_pipeline","description":"Plan → Parallel Dev → Integrate"}},{"id":"output_1","type":"adk-output","position":{"x":1400,"y":250},"data":{"label":"Delivery Package"}}],"edges":[{"id":"e1","source":"input_1","target":"pipeline","animated":true},{"id":"e2","source":"planner","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e3","source":"dev_frontend","target":"parallel_dev","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e4","source":"dev_backend","target":"parallel_dev","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e5","source":"dev_tests","target":"parallel_dev","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e6","source":"parallel_dev","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e7","source":"integrator","target":"pipeline","targetHandle":"sub-agents","animated":true,"label":"sub-agent"},{"id":"e8","source":"pipeline","target":"output_1","animated":true}]}'),

-- ═══════════════════════════════════════════════════════════════
-- Template 8: Callbacks & Guardrails Demo (ADK Safety Pattern)
-- ═══════════════════════════════════════════════════════════════
('adk-callbacks-guardrails', 'Callbacks & Guardrails (Safety Pattern)', 'Demonstrates all 6 ADK callbacks used as guardrails: before_agent (rate limit), before_model (content filter), after_model (output sanitize), before_tool (policy check), after_tool (audit log). Full safety pattern.', 'google-adk', 'single-agent', NULL, 'advanced', '["callbacks", "guardrails", "safety", "content-filter", "audit", "policy", "adk"]', 'https://google.github.io/adk-docs/callbacks/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":200},"data":{"label":"User Input"}},{"id":"agent_1","type":"adk-llm-agent","position":{"x":420,"y":180},"data":{"label":"Guarded Agent","name":"guarded_agent","model":"gemini-2.0-flash","modelProvider":"gemini","instruction":"You are a helpful assistant that follows strict safety guidelines. You never reveal personal data, generate harmful content, or execute unauthorized actions.","description":"Agent with full callback guardrails","outputKey":"response","beforeAgentCallback":true,"afterAgentCallback":true,"beforeModelCallback":true,"afterModelCallback":true,"beforeToolCallback":true,"afterToolCallback":true,"temperature":0.7,"maxOutputTokens":2048}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":400,"y":40},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"tool_validate","type":"adk-function-tool","position":{"x":600,"y":40},"data":{"label":"PII Detector","functionName":"detect_pii","description":"Scans text for personally identifiable information (emails, phones, SSN)","code":"    import re\\n    pii_found = []\\n    if re.search(r''[\\w.-]+@[\\w.-]+\\.\\w+'', query):\\n        pii_found.append(\"email\")\\n    if re.search(r''\\b\\d{3}[-.]?\\d{3}[-.]?\\d{4}\\b'', query):\\n        pii_found.append(\"phone\")\\n    return {\"has_pii\": len(pii_found) > 0, \"types\": pii_found}"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":200},"data":{"label":"Safe Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent_1","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e3","source":"tool_validate","target":"agent_1","targetHandle":"tools","animated":true,"label":"tool"},{"id":"e4","source":"agent_1","sourceHandle":"output","target":"output_1","animated":true}]}');
